      const fallback = {
        top: "35%",
        left: "40%",
        size: 110
      };
      if (this.selectedBubbleRecordId && index === 0) {
        return focusLayout;
      }
      if (this.selectedBubbleRecordId) {
        return this.getGeneratedBubbleLayout(index - 1, true) || fallback;
      }
      return this.getGeneratedBubbleLayout(index, false) || fallback;
    },
    getGeneratedBubbleLayout(index, isSelectedState) {
