      const columnGap = isSelectedState ? 11.5 : 14;
      const rowGap = isSelectedState ? 12.5 : 14;
      const baseLeft = isSelectedState ? 3 : 5;
      const baseTop = isSelectedState ? 6 : 5;
      const row = Math.floor(index / columns);
      const col = index % columns;
      const size = sizePattern[index % sizePattern.length];
      const leftOffset = row % 2 === 0 ? 0 : isSelectedState ? 4.5 : 3.5;
      const topOffset = isSelectedState ? [0, 3, 1, 4][col % 4] : col % 2 === 0 ? 0 : 2;
