      const boardRect = board.getBoundingClientRect();
      const maxX = Math.max(boardRect.width - drag.width, 0);
      const maxY = Math.max(boardRect.height - drag.height, 0);
      const nextX = Math.min(Math.max(event.clientX - boardRect.left - drag.offsetX, 0), maxX);
      const nextY = Math.min(Math.max(event.clientY - boardRect.top - drag.offsetY, 0), maxY);
      this.bubblePositions = {
        ...this.bubblePositions,
        [drag.id]: {
